#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline char Get(){char ch;do ch=getchar();while(ch!='Q'&&ch!='P');return ch;}
const int N=1e5+10;int head[N],des[N<<1],nxt[N<<1],cgt,n,idx[N],dep[N],siz[N],fa[N],top[N],mxs[N],t[N],cdt;
inline void add(int l,int r){++r;while(l<=n)++t[l],l+=(l&-l);while(r<=n)--t[r],r+=(r&-r);}
inline int qry(int p){int res=0;while(p)res+=t[p],p^=(p&-p);return res;}
inline void ins(const int &x,const int &y){nxt[++cgt]=head[x];des[head[x]=cgt]=y;nxt[++cgt]=head[y];des[head[y]=cgt]=x;}
inline void dfs1(const int &u=1,const int &f=0)
{
	dep[u]=dep[fa[u]=f]+1;siz[u]=1;int mx=0;
	grep(u,i)if(des[i]!=f){int v=des[i];dfs1(v,u);siz[u]+=siz[v];mx<siz[v]?mx=siz[mxs[u]=v]:0;}
}
inline void dfs2(const int &u=1,const int &fa=0,const int &tp=1)
{
	idx[u]=++cdt;top[u]=tp;if(mxs[u])dfs2(mxs[u],u,tp);
	grep(u,i)if(des[i]!=fa&&des[i]!=mxs[u])dfs2(des[i],u,des[i]);
}
inline void Add(int u,int v)
{
	while(top[u]!=top[v])
	{
		dep[top[u]]<dep[top[v]]?
		(add(idx[top[v]],idx[v]),v=fa[top[v]]):
		(add(idx[top[u]],idx[u]),u=fa[top[u]]);
	}
	dep[u]<dep[v]?add(idx[u]+1,idx[v]):add(idx[v]+1,idx[u]);
}
inline void Qry(int u,int v){printf("%d\n",qry(idx[dep[u]<dep[v]?v:u]));}
int main()
{
	n=read();int Q=read();rep(2,n,i)ins(read(),read());dfs1();dfs2();
	while(Q--){Get()=='P'?Add(read(),read()):Qry(read(),read());}
}
